from typing import List

def contains_nearby_duplicate(nums: List[int], k: int) -> bool:
    window = set()
    for i, n in enumerate(nums):
        if n in window:
            return True
        window.add(n)
        if len(window) > k:
            window.remove(nums[i - k])
    return False
